document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".navbar");window.addEventListener("scroll",()=>{window.scrollY>50?e.classList.add("scrolled"):e.classList.remove("scrolled")}),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=document.querySelector(this.getAttribute("href"));t&&t.scrollIntoView({behavior:"smooth"})})});const t=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("animate-in"),t.unobserve(e.target))})},{threshold:.1});document.querySelectorAll(".section-title, .card, .project-card, .timeline-item").forEach(e=>{e.style.opacity="0",e.style.transform="translateY(20px)",e.style.transition="opacity 0.6s ease-out, transform 0.6s ease-out",t.observe(e)});const n=document.createElement("style");n.textContent="\n        .animate-in {\n            opacity: 1 !important;\n            transform: translateY(0) !important;\n        }\n    ",document.head.appendChild(n)});